### 阶段 1：创建集成模块（Day 1）

#### 1.1 创建 `DashboardNotifier` 类

**文件**: `src/dashboard/integration.ts` (新建)

```typescript
/**
 * Dashboard 集成模块
 *
 * 连接 AutoIterationEngine 和 Dashboard 服务
 */

import pino from 'pino';
import {
  IterationService,
  AgentService,
  RealtimeService
} from './services';
import {
  IterationStatus,
  AgentType,
  IterationStatusChange,
  AgentStatusChange,
  IterationProgress
} from './types';

// ==================== Dashboard Notifier ====================

export class DashboardNotifier {
  private currentIterationId: number | null = null;
  private currentIterationNumber: number = 0;

  constructor(
    private logger: pino.Logger,
    private iterationService: IterationService,
    private agentService: AgentService,
    private realtimeService: RealtimeService
  ) {}

  /**
   * 迭代开始通知
   */
  async notifyIterationStart(
    iterationNumber: number,
    requirement: string
  ): Promise<number> {
    this.logger.info(
      { iterationNumber, requirement },
      '[Dashboard] Iteration started'
    );

    // 创建迭代记录
    const iteration = this.iterationService.create({
      iterationNumber,
      status: IterationStatus.RUNNING,
      requirement,
      startedAt: new Date()
    });

    this.currentIterationId = iteration.id;
    this.currentIterationNumber = iterationNumber;

    // 广播状态变化
    this.realtimeService.broadcastIterationStatusChange({
      iterationId: iteration.id,
      iterationNumber: iteration.iterationNumber,
      status: IterationStatus.RUNNING,
      timestamp: new Date()
    });

    // 广播进度
    this.realtimeService.broadcastIterationProgress({
      iterationId: iteration.id,
      phase: 'product_manager',
      progress: 0,
      message: '迭代开始',
      timestamp: new Date()
    });

    return iteration.id;
  }

  /**
   * Agent 执行通知
   */
  async notifyAgentStart(
    agentType: AgentType,
    task: string
  ): Promise<void> {
    if (!this.currentIterationId) {
      this.logger.warn('[Dashboard] No active iteration');
      return;
    }

    this.logger.info(
      { agentType, task },
      '[Dashboard] Agent started'
    );

    // 创建 Agent 状态记录
    this.agentService.upsert({
      iterationId: this.currentIterationId,
      agentName: agentType,
      agentType,
      status: 'running',
      currentTask: task,
      progress: 0,
      startedAt: new Date()
    });

    // 广播 Agent 状态
    this.realtimeService.broadcastAgentStatusChange({
      iterationId: this.currentIterationId,
      agentName: agentType,
      agentType,
      status: 'running',
      progress: 0,
      timestamp: new Date()
    });

    // 广播进度
    this.realtimeService.broadcastIterationProgress({
      iterationId: this.currentIterationId,
      phase: agentType,
      progress: 10,
      message: `${agentType} 开始执行: ${task}`,
      timestamp: new Date()
    });
  }

  /**
   * Agent 进度更新
   */
  async notifyAgentProgress(
    agentType: AgentType,
    progress: number,
    message: string
  ): Promise<void> {
    if (!this.currentIterationId) return;

    // 更新 Agent 进度
    this.agentService.updateProgress(
      this.currentIterationId,
      agentType,
      progress,
      message
    );

    // 广播进度
    this.realtimeService.broadcastIterationProgress({
      iterationId: this.currentIterationId,
      phase: agentType,
      progress,
      message,
      timestamp: new Date()
    });
  }

  /**
   * Agent 完成通知
   */
  async notifyAgentComplete(
    agentType: AgentType,
    output: string,
    executionTimeSeconds: number,
    tokensUsed: number
  ): Promise<void> {
    if (!this.currentIterationId) return;

    this.logger.info(
      { agentType, executionTimeSeconds, tokensUsed },
      '[Dashboard] Agent completed'
    );

    // 标记 Agent 完成
    this.agentService.markCompleted(
      this.currentIterationId,
      agentType,
      output,
      executionTimeSeconds,
      tokensUsed
    );

    // 广播状态
    this.realtimeService.broadcastAgentStatusChange({
      iterationId: this.currentIterationId,
      agentName: agentType,
      agentType,
      status: 'completed',
      progress: 100,
      timestamp: new Date()
    });
  }

  /**
   * Agent 失败通知
   */
  async notifyAgentError(
    agentType: AgentType,
    errorMessage: string
  ): Promise<void> {
    if (!this.currentIterationId) return;

    this.logger.error(
      { agentType, errorMessage },
      '[Dashboard] Agent failed'
    );

    // 标记 Agent 失败
    this.agentService.markFailed(
      this.currentIterationId,
      agentType,
      errorMessage
    );

    // 广播状态
    this.realtimeService.broadcastAgentStatusChange({
      iterationId: this.currentIterationId,
      agentName: agentType,
      agentType,
      status: 'error',
      progress: 0,
      timestamp: new Date()
    });
  }

  /**
   * 迭代完成通知
   */
  async notifyIterationComplete(
    architectResult?: string,
    uiResult?: string,
    backendResult?: string,
    databaseResult?: string,
    frontendResult?: string,
    assetsResult?: string,
    testResult?: string,
    securityResult?: string,
    docResult?: string
  ): Promise<void> {
    if (!this.currentIterationId) return;

    this.logger.info(
      { iterationId: this.currentIterationId },
      '[Dashboard] Iteration completed'
    );

    // 获取迭代开始时间
    const iteration = this.iterationService.findById(this.currentIterationId);
    const startedAt = iteration?.startedAt || new Date();
    const durationSeconds = Math.floor(
      (Date.now() - startedAt.getTime()) / 1000
    );

    // 更新迭代
    this.iterationService.update(this.currentIterationId, {
      status: IterationStatus.COMPLETED,
      completedAt: new Date(),
      durationSeconds,
      architectResult,
      uiResult,
      backendResult,
      databaseResult,
      frontendResult,
      assetsResult,
      testResult,
      securityResult,
      docResult
    });

    // 广播完成状态
    this.realtimeService.broadcastIterationStatusChange({
      iterationId: this.currentIterationId,
      iterationNumber: this.currentIterationNumber,
      status: IterationStatus.COMPLETED,
      timestamp: new Date()
    });

    // 广播最终进度
    this.realtimeService.broadcastIterationProgress({
      iterationId: this.currentIterationId,
      phase: 'complete',
      progress: 100,
      message: '迭代完成',
      timestamp: new Date()
    });
  }

  /**
   * 迭代失败通知
   */
  async notifyIterationError(errorMessage: string): Promise<void> {
    if (!this.currentIterationId) return;

    this.logger.error(
      { iterationId: this.currentIterationId, errorMessage },
      '[Dashboard] Iteration failed'
    );

    // 更新迭代
    this.iterationService.update(this.currentIterationId, {
      status: IterationStatus.FAILED,
      completedAt: new Date(),
      errorMessage
    });

    // 广播失败状态
    this.realtimeService.broadcastIterationStatusChange({
      iterationId: this.currentIterationId,
      iterationNumber: this.currentIterationNumber,
      status: IterationStatus.FAILED,
      timestamp: new Date()
    });
  }

  /**
   * Git 提交通知
   */
  async notifyGitCommit(
    commitHash: string,
    commitMessage: string,
    branch: string
  ): Promise<void> {
    if (!this.currentIterationId) return;

    this.logger.info(
      { commitHash, branch },
      '[Dashboard] Git commit'
    );

    // 更新迭代
    this.iterationService.update(this.currentIterationId, {
      commitHash,
      commitMessage,
      branch
    });
  }
}

// ==================== 导出服务访问器 ====================

let notifier: DashboardNotifier | null = null;

export function initDashboardNotifier(logger: pino.Logger): DashboardNotifier {
  if (notifier) {
    return notifier;
  }

  // 动态导入服务（避免循环依赖）
  const services = require('./server');

  notifier = new DashboardNotifier(
    logger,
    services.iterationService,
    services.agentService,
    services.realtimeService
  );

  return notifier;
}

export function getDashboardNotifier(): DashboardNotifier | null {
  return notifier;
}
```

